const n = parseInt(process.argv[2]);
let total = 0;
for (let i = 1; i <= n; i++) {
    let k = i;
    while (k !== 1) {
        if (k % 2 === 0) k = k / 2;
        else k = 3 * k + 1;
        total++;
    }
}
console.log(total);

const limit = parseInt(process.argv[2]);
const sieve = new Uint8Array(limit + 1);
let count = 0;
for (let i = 2; i <= limit; i++) {
    if (!sieve[i]) {
        count++;
        for (let j = i * i; j <= limit; j += i)
            sieve[j] = 1;
    }
}
console.log(count);

const n = parseInt(process.argv[2]);
let count = 0;
for (let i = 2; i <= n; i++) {
    let isPrime = true;
    for (let d = 2; d * d <= i; d++) {
        if (i % d === 0) { isPrime = false; break; }
    }
    if (isPrime) count++;
}
console.log(count);

const n = parseInt(process.argv[2]);
const counts = new Array(1000).fill(0);
let seed = 42;
for (let i = 0; i < n; i++) {
    seed = ((Math.imul(seed, 1103515245) + 12345) >>> 0) % 2147483648;
    counts[((seed >> 16) & 0x7fff) % 1000]++;
}
let maxFreq = 0, maxIdx = 0, distinct = 0;
for (let i = 0; i < 1000; i++) {
    if (counts[i] > 0) distinct++;
    if (counts[i] > maxFreq) { maxFreq = counts[i]; maxIdx = i; }
}
console.log(`${maxFreq} ${maxIdx} ${distinct}`);

