const n = parseInt(process.argv[2]);
const capacity = n * 5;
let prev = new Array(capacity + 1).fill(0);
let curr = new Array(capacity + 1).fill(0);
for (let i = 0; i < n; i++) {
    const w = (i * 17 + 3) % 50 + 1, v = (i * 31 + 7) % 100 + 1;
    for (let j = 0; j <= capacity; j++) {
        curr[j] = prev[j];
        if (j >= w && prev[j - w] + v > curr[j]) curr[j] = prev[j - w] + v;
    }
    [prev, curr] = [curr, prev];
}
console.log(prev[capacity]);

const n = parseInt(process.argv[2]);
const coins = [1, 5, 10, 25, 50, 100];
const dp = new Array(n + 1).fill(0);
dp[0] = 1;
for (const c of coins) for (let j = c; j <= n; j++) dp[j] = (dp[j] + dp[j - c]) % 1000000007;
console.log(dp[n]);

function gcd(a, b) {
    while (b > 0) { const t = b; b = a % b; a = t; }
    return a;
}
const n = parseInt(process.argv[2]);
let sum = 0;
for (let i = 1; i <= n; i++)
    for (let j = i; j <= n; j++)
        sum += gcd(i, j);
console.log(sum);

const MAX_EDGES = 5;
const n = parseInt(process.argv[2]);
const primes = [31, 37, 41, 43, 47];
const offsets = [7, 13, 17, 23, 29];
const adj = new Int32Array(n * MAX_EDGES);
const adjCount = new Int32Array(n);
for (let p = 0; p < MAX_EDGES; p++) {
    for (let i = 0; i < n; i++) {
        const neighbor = (i * primes[p] + offsets[p]) % n;
        if (neighbor !== i) {
            adj[i * MAX_EDGES + adjCount[i]] = neighbor;
            adjCount[i]++;
        }
    }
}
const queue = new Int32Array(n);
const dist = new Int32Array(n).fill(-1);
let front = 0, back = 0;
queue[back++] = 0;
dist[0] = 0;
while (front < back) {
    const v = queue[front++];
    for (let e = 0; e < adjCount[v]; e++) {
        const u = adj[v * MAX_EDGES + e];
        if (dist[u] === -1) { dist[u] = dist[v] + 1; queue[back++] = u; }
    }
}
let reachable = 0, totalDist = 0;
for (let i = 0; i < n; i++) {
    if (dist[i] >= 0) { reachable++; totalDist += dist[i]; }
}
console.log(reachable + " " + totalDist);

function solve(row, cols, diag1, diag2, n) {
    if (row === n) return 1;
    let count = 0;
    let available = ((1 << n) - 1) & ~(cols | diag1 | diag2);
    while (available) {
        const bit = available & (-available);
        available ^= bit;
        count += solve(row + 1, cols | bit, (diag1 | bit) << 1, (diag2 | bit) >> 1, n);
    }
    return count;
}
const n = parseInt(process.argv[2]);
console.log(solve(0, 0, 0, 0, n));

const n = parseInt(process.argv[2]);
const perm1 = Array.from({length: n}, (_, i) => i);
const count = new Array(n).fill(0);
let maxFlips = 0, checksum = 0, permCount = 0, r = n;
outer: while (true) {
    while (r > 1) { count[r-1] = r; r--; }
    const perm = [...perm1];
    let flips = 0;
    while (perm[0] !== 0) {
        const k = perm[0] + 1;
        for (let i = 0; i < k >> 1; i++) { const t = perm[i]; perm[i] = perm[k-1-i]; perm[k-1-i] = t; }
        flips++;
    }
    if (flips > maxFlips) maxFlips = flips;
    checksum += (permCount % 2 === 0) ? flips : -flips;
    permCount++;
    while (true) {
        if (r === n) break outer;
        const p0 = perm1[0];
        for (let i = 0; i < r; i++) perm1[i] = perm1[i+1];
        perm1[r] = p0;
        if (--count[r] > 0) break;
        r++;
    }
}
console.log(checksum + "\n" + maxFlips);
